import { useCallback, useEffect, useRef, useState } from "react";

import api from "../../api/client.js";
import { showToastDedup } from "../../lib/toastDedup.js";

function renderResult(result) {
  if (typeof result === "string") return result;
  try {
    return JSON.stringify(result ?? {}, null, 2);
  } catch {
    return String(result ?? "");
  }
}

function normalizeStep(raw, idx) {
  if (raw && typeof raw === "object") {
    return {
      id: String(raw.id || `s${idx + 1}`),
      label: String(raw.label || `Step ${idx + 1}`),
      status: String(raw.status || "pending"),
    };
  }
  return { id: `s${idx + 1}`, label: String(raw || `Step ${idx + 1}`), status: "pending" };
}

function asList(value) {
  if (Array.isArray(value)) return value.map((x) => String(x)).filter(Boolean);
  if (typeof value === "string" && value.trim()) return [value.trim()];
  return [];
}

function summarizeResult(result) {
  if (result == null) return "Execution completed.";
  if (typeof result === "string") return result.slice(0, 240);
  if (typeof result !== "object") return String(result);
  return String(
    result.summary ||
      result.message ||
      result.overview ||
      result.insight ||
      result.title ||
      "Execution completed successfully.",
  );
}

function buildReadableSections(message) {
  const result = message?.result;
  const steps = Array.isArray(message?.steps) ? message.steps : [];
  const summary = summarizeResult(result);

  const analysis = asList(result?.analysis || result?.highlights || result?.observations || result?.findings);
  const issues = asList(result?.issues || result?.risks || result?.errors || result?.warnings);
  const actions = asList(result?.actions || result?.next_steps || result?.recommendations);
  const data = result && typeof result === "object" ? result.data || result.metrics || result : result;

  return { summary, analysis, issues, actions, data, steps };
}

export default function AIAssistantPanel() {
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);
  const [listening, setListening] = useState(false);
  const [messages, setMessages] = useState([]);
  const [conversations, setConversations] = useState([]);
  const [activeConversationId, setActiveConversationId] = useState(null);
  const [loadingConversations, setLoadingConversations] = useState(false);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const recognitionRef = useRef(null);
  const endRef = useRef(null);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  const refreshConversations = useCallback(async () => {
    setLoadingConversations(true);
    try {
      const { data } = await api.get("/execute/conversations", { params: { limit: 40 } });
      setConversations(Array.isArray(data) ? data : []);
    } catch {
      setConversations([]);
    } finally {
      setLoadingConversations(false);
    }
  }, []);

  useEffect(() => {
    refreshConversations();
  }, [refreshConversations]);

  const loadConversation = useCallback(async (conversationId) => {
    if (!conversationId) return;
    setActiveConversationId(Number(conversationId));
    setLoadingHistory(true);
    try {
      const { data } = await api.get(`/execute/conversations/${encodeURIComponent(conversationId)}/messages`, {
        params: { limit: 200 },
      });
      const mapped = (Array.isArray(data) ? data : []).map((row, idx) => {
        const meta = row?.metadata && typeof row.metadata === "object" ? row.metadata : {};
        if (row?.role === "user") {
          return {
            role: "user",
            text: String(row?.content || ""),
            ts: Date.parse(row?.created_at || "") || Date.now() + idx,
          };
        }
        return {
          role: "assistant",
          text: String(row?.content || ""),
          ts: Date.parse(row?.created_at || "") || Date.now() + idx,
          executionId: String(meta?.execution_id || ""),
          intent: meta?.intent ? String(meta.intent) : "",
          steps: Array.isArray(meta?.steps) ? meta.steps.map(normalizeStep) : [],
          result: Object.prototype.hasOwnProperty.call(meta, "result") ? meta.result : row?.content,
          status: String(meta?.status || ""),
          error: meta?.error ? String(meta.error) : "",
        };
      });
      setMessages(mapped);
    } catch (e) {
      const d = e?.response?.data?.detail;
      const err = typeof d === "string" ? d : e?.message || "Unable to load conversation";
      showToastDedup({ type: "error", message: err });
    } finally {
      setLoadingHistory(false);
    }
  }, []);

  const startNewConversation = useCallback(() => {
    setActiveConversationId(null);
    setMessages([]);
  }, []);

  const submit = useCallback(
    async (textOverride = "") => {
      const text = String(textOverride || message).trim();
      if (!text || loading) return;
      setLoading(true);
      setMessages((prev) => [...prev, { role: "user", text, ts: Date.now() }]);
      if (!textOverride) setMessage("");
      try {
        const { data } = await api.post("/execute", {
          command: text,
          conversation_id: activeConversationId,
        });
        const nextConversationId = Number(data?.conversation_id || 0) || null;
        if (nextConversationId && nextConversationId !== activeConversationId) {
          setActiveConversationId(nextConversationId);
        }
        setMessages((prev) => [
          ...prev,
          {
            role: "assistant",
            ts: Date.now(),
            executionId: String(data?.execution_id || ""),
            intent: String(data?.intent || "unknown"),
            steps: Array.isArray(data?.steps) ? data.steps.map(normalizeStep) : [],
            result: data?.result,
            status: String(data?.status || ""),
          },
        ]);
        refreshConversations();
      } catch (e) {
        const d = e?.response?.data?.detail;
        const err = typeof d === "string" ? d : e?.message || "Execute failed";
        setMessages((prev) => [...prev, { role: "assistant", ts: Date.now(), error: err }]);
        showToastDedup({ type: "error", message: err });
      } finally {
        setLoading(false);
      }
    },
    [activeConversationId, loading, message, refreshConversations],
  );

  const startVoice = useCallback(() => {
    if (typeof window === "undefined") return;
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      showToastDedup({ type: "warning", message: "Voice input not supported in this browser" });
      return;
    }
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch {
        /* ignore */
      }
      recognitionRef.current = null;
    }
    const rec = new SR();
    rec.lang = "en-IN";
    rec.continuous = false;
    rec.interimResults = false;
    rec.maxAlternatives = 1;
    recognitionRef.current = rec;
    setListening(true);
    rec.onend = () => {
      recognitionRef.current = null;
      setListening(false);
    };
    rec.onerror = () => {
      recognitionRef.current = null;
      setListening(false);
      showToastDedup({ type: "warning", message: "Voice input failed. Please try again." });
    };
    rec.onresult = (ev) => {
      const spoken = String(ev.results?.[0]?.[0]?.transcript || "").trim();
      if (!spoken) return;
      setMessage(spoken);
      submit(spoken);
    };
    try {
      rec.start();
    } catch {
      setListening(false);
      recognitionRef.current = null;
    }
  }, [submit]);

  return (
    <div className="mx-auto grid w-full max-w-6xl grid-cols-1 gap-4 md:grid-cols-12">
      <aside className="rounded-xl border border-slate-800 bg-slate-900/60 p-3 md:col-span-4 lg:col-span-3">
        <div className="mb-3 flex items-center justify-between">
          <h3 className="text-sm font-semibold text-slate-100">Conversations</h3>
          <button
            type="button"
            onClick={startNewConversation}
            className="rounded-md border border-slate-700 px-2 py-1 text-xs text-slate-200 hover:bg-slate-800"
          >
            New
          </button>
        </div>
        <div className="max-h-[68vh] space-y-1 overflow-y-auto">
          {loadingConversations ? (
            <div className="text-xs text-slate-400">Loading...</div>
          ) : conversations.length === 0 ? (
            <div className="text-xs text-slate-400">No saved conversations yet.</div>
          ) : (
            conversations.map((conv) => {
              const active = Number(conv.id) === Number(activeConversationId);
              return (
                <button
                  type="button"
                  key={conv.id}
                  onClick={() => loadConversation(conv.id)}
                  className={`w-full rounded-lg border px-3 py-2 text-left text-sm ${
                    active
                      ? "border-blue-500/60 bg-blue-500/10 text-blue-100"
                      : "border-slate-800 bg-slate-950/40 text-slate-200 hover:bg-slate-800/60"
                  }`}
                >
                  <div className="truncate">{conv.title || `Conversation ${conv.id}`}</div>
                </button>
              );
            })
          )}
        </div>
      </aside>

      <section className="flex flex-col gap-4 md:col-span-8 lg:col-span-9">
        <div className="rounded-xl border border-slate-800 bg-slate-900/60 p-4">
          <h2 className="text-lg font-semibold text-slate-100">Jarvis</h2>
          <p className="mt-1 text-sm text-slate-400">
            Ask anything. I will execute via `/execute` with conversation memory and show intent, steps, result, and execution id.
          </p>
        </div>

        <div className="max-h-[62vh] overflow-y-auto rounded-xl border border-slate-800 bg-slate-900/50 p-4">
          {loadingHistory ? (
            <div className="rounded-lg border border-slate-700 p-4 text-sm text-slate-400">Loading conversation history...</div>
          ) : null}
        {messages.length === 0 ? (
          <div className="rounded-lg border border-dashed border-slate-700 p-6 text-center text-sm text-slate-400">
            Start by typing or using voice.
          </div>
        ) : null}

        <div className="space-y-3">
          {messages.map((m, idx) => {
            if (m.role === "user") {
              return (
                <div key={`u_${m.ts}_${idx}`} className="flex justify-end">
                  <div className="max-w-[85%] rounded-2xl bg-blue-600/20 px-4 py-2 text-sm text-slate-100">{m.text}</div>
                </div>
              );
            }
            return (
              <div key={`a_${m.ts}_${idx}`} className="flex justify-start">
                <div className="w-full max-w-[92%] rounded-2xl border border-slate-700 bg-slate-900 px-4 py-3 text-sm text-slate-100">
                  {m.error ? (
                    <div className="text-red-300">{m.error}</div>
                  ) : (
                    (() => {
                      const readable = buildReadableSections(m);
                      return (
                        <div className="space-y-3">
                          <div className="rounded-lg border border-slate-700 bg-slate-950/60 p-3">
                            <div className="text-xs uppercase tracking-wide text-slate-400">🧠 Insight</div>
                            <div className="mt-1 text-sm text-slate-100">{readable.summary}</div>
                            <div className="mt-2 text-xs text-slate-400">
                              intent: <span className="font-medium text-blue-300">{m.intent || "unknown"}</span>
                            </div>
                          </div>

                          {readable.analysis.length > 0 ? (
                            <div className="rounded-lg border border-slate-700 bg-slate-950/50 p-3">
                              <div className="mb-1 text-xs uppercase tracking-wide text-slate-400">Analysis</div>
                              <ul className="list-disc space-y-1 pl-5 text-sm text-slate-100">
                                {readable.analysis.map((entry, i) => (
                                  <li key={`${m.ts}_an_${i}`}>{entry}</li>
                                ))}
                              </ul>
                            </div>
                          ) : null}

                          {readable.issues.length > 0 ? (
                            <div className="rounded-lg border border-amber-500/30 bg-amber-500/10 p-3">
                              <div className="mb-1 text-xs uppercase tracking-wide text-amber-300">⚠️ Issues</div>
                              <ul className="list-disc space-y-1 pl-5 text-sm text-amber-100">
                                {readable.issues.map((entry, i) => (
                                  <li key={`${m.ts}_is_${i}`}>{entry}</li>
                                ))}
                              </ul>
                            </div>
                          ) : null}

                          {readable.actions.length > 0 ? (
                            <div className="rounded-lg border border-emerald-500/30 bg-emerald-500/10 p-3">
                              <div className="mb-1 text-xs uppercase tracking-wide text-emerald-300">💡 Actions</div>
                              <ul className="list-disc space-y-1 pl-5 text-sm text-emerald-100">
                                {readable.actions.map((entry, i) => (
                                  <li key={`${m.ts}_ac_${i}`}>{entry}</li>
                                ))}
                              </ul>
                            </div>
                          ) : null}

                          <div className="rounded-lg border border-slate-700 bg-slate-950/50 p-3">
                            <div className="mb-1 text-xs uppercase tracking-wide text-slate-400">📊 Data</div>
                            {readable.steps.length > 0 ? (
                              <div className="space-y-1.5">
                                {readable.steps.map((s, i) => {
                                  const st = String(s?.status || "pending").toLowerCase();
                                  return (
                                    <div key={`${m.ts}_s_${i}`} className="flex items-center gap-2 text-sm">
                                      <span
                                        className={`inline-flex h-2.5 w-2.5 rounded-full ${
                                          st === "done"
                                            ? "bg-emerald-400"
                                            : st === "running"
                                              ? "animate-pulse bg-blue-400"
                                              : "bg-slate-600"
                                        }`}
                                      />
                                      <span
                                        className={`${
                                          st === "done"
                                            ? "text-emerald-200"
                                            : st === "running"
                                              ? "text-blue-200"
                                              : "text-slate-400"
                                        }`}
                                      >
                                        {s.label}
                                      </span>
                                    </div>
                                  );
                                })}
                              </div>
                            ) : (
                              <div className="text-sm text-slate-400">No process steps were returned.</div>
                            )}
                            {m.executionId ? (
                              <div className="mt-2 text-[11px] text-slate-500">execution_id: {m.executionId}</div>
                            ) : null}
                          </div>

                          <details className="rounded-lg border border-slate-700 bg-slate-950/40 p-3">
                            <summary className="cursor-pointer text-xs text-slate-400">View technical details</summary>
                            <div className="mt-2 space-y-2">
                              <div className="text-xs text-slate-400">
                                status: <span className="text-slate-200">{m.status || "unknown"}</span>
                              </div>
                              <pre className="max-h-56 overflow-auto rounded-lg bg-slate-950 p-3 text-xs text-slate-200">
                                {renderResult(readable.data)}
                              </pre>
                            </div>
                          </details>
                        </div>
                      );
                    })()
                  )}
                </div>
              </div>
            );
          })}
          {loading ? (
            <div className="rounded-xl border border-slate-700 bg-slate-900/60 p-3 text-xs text-slate-400">
              Executing command...
            </div>
          ) : null}
          <div ref={endRef} />
        </div>
        </div>

        <div className="rounded-xl border border-slate-800 bg-slate-900/60 p-3">
          <div className="flex gap-2">
            <input
              className="flex-1 rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none ring-blue-500/40 focus:ring-2"
              placeholder="Type a command..."
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") submit();
              }}
            />
            <button
              type="button"
              onClick={() => submit()}
              disabled={loading}
              className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-500 disabled:opacity-60"
            >
              Send
            </button>
            <button
              type="button"
              onClick={startVoice}
              disabled={loading || listening}
              className="rounded-lg border border-slate-700 px-4 py-2 text-sm text-slate-200 hover:bg-slate-800 disabled:opacity-60"
              title="Voice input"
            >
              {listening ? "Listening..." : "Voice"}
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}
